```sparql
SELECT DISTINCT ?kerouacBook ?harryPotterAuthor ?topPoet WHERE {
  # Books by Kerouac published by Viking Press
  {
    SELECT DISTINCT ?kerouacBook WHERE {
      ?kerouacBook <http://www.wikidata.org/prop/direct/P123> <http://www.wikidata.org/entity/Q921536>.
      ?kerouacBook <http://www.wikidata.org/prop/direct/P31> <http://www.wikidata.org/entity/Q47461344>.
      ?kerouacBook <http://www.wikidata.org/prop/direct/P50> <http://www.wikidata.org/entity/Q160534>.
    }
  }
  # Author of Harry Potter
  {
    SELECT DISTINCT ?harryPotterAuthor WHERE {
      <http://www.wikidata.org/entity/Q8337> <http://www.wikidata.org/prop/direct/P50> ?harryPotterAuthor.
    }
  }
  # Poet who wrote the most books
  {
    SELECT ?topPoet WHERE {
      ?topPoet <http://www.wikidata.org/prop/direct/P106> <http://www.wikidata.org/entity/Q49757>.
      ?book <http://www.wikidata.org/prop/direct/P50> ?topPoet.
      ?book <http://www.wikidata.org/prop/direct/P31> <http://www.wikidata.org/entity/Q571>.
    } GROUP BY ?topPoet
    ORDER BY DESC(COUNT(?book))
    LIMIT 1
  }
}
```

