```PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#> 
PREFIX wdt: <http://www.wikidata.org/prop/direct/> 
PREFIX wd: <http://www.wikidata.org/entity/> 

SELECT ?youngestMVP ?redSoxStadium ?tallPlayer WHERE {
  {
    ?youngestMVP wdt:P106 wd:Q3665646 ;     # occupation: basketball player
                 wdt:P569 ?birthDate ;     # date of birth
                 wdt:P166 ?award .         # awards received

    ?award rdfs:label ?awardLabel .
    FILTER(CONTAINS(LCASE(?awardLabel), "mvp") || CONTAINS(LCASE(?awardLabel), "most valuable player"))
    FILTER(LANGMATCHES(LANG(?awardLabel), "EN"))
  }
  UNION
  {
    wd:Q213959 wdt:P115 ?redSoxStadium .    # Red Sox home stadium
  }
  UNION
  {
    ?tallPlayer wdt:P106 wd:Q3665646 ;     # basketball player
                wdt:P2048 ?height .        # height in centimeters
    FILTER(?height > 200)
  }
}
ORDER BY ASC(?birthDate)
LIMIT 4
```

