```PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?question ?countOrMovie WHERE {
  VALUES (?question) {
    ("How many films did Leonardo DiCaprio star in?"^^xsd:string)
    ("In which films directed by Garry Marshall was Julia Roberts starring?"^^xsd:string)
    ("What movies does Jesse Eisenberg play in?"^^xsd:string)
  }
  BIND (
    IF(
      ?question = "How many films did Leonardo DiCaprio star in?",
      "count",
      "list"
    ) AS ?type
  )
  FILTER (
    ?question = "How many films did Leonardo DiCaprio star in?"
    || ?question = "In which films directed by Garry Marshall was Julia Roberts starring?"
    || ?question = "What movies does Jesse Eisenberg play in?"
  )

  # For counting Leonardo DiCaprio movies
  OPTIONAL {
    FILTER(?question = "How many films did Leonardo DiCaprio star in?")
    {
      SELECT (COUNT(DISTINCT ?film) AS ?count) WHERE {
        ?film wdt:P31 wd:Q11424 ;
              wdt:P161 wd:Q38111 .
      }
    }
  }

  # For films directed by Garry Marshall with Julia Roberts starring
  OPTIONAL {
    FILTER(?question = "In which films directed by Garry Marshall was Julia Roberts starring?")
    {
      SELECT DISTINCT ?film WHERE {
        ?film wdt:P31 wd:Q11424 ;
              wdt:P57 wd:Q315087 ;
              wdt:P161 wd:Q40523 .
      }
    }
  }

  # For movies Jesse Eisenberg plays in
  OPTIONAL {
    FILTER(?question = "What movies does Jesse Eisenberg play in?")
    {
      SELECT DISTINCT ?film WHERE {
        ?film wdt:P161 wd:Q219512 .
      }
    }
  }

  BIND(
    IF(?question = "How many films did Leonardo DiCaprio star in?", STR(?count),
       IF(?question = "In which films directed by Garry Marshall was Julia Roberts starring?", STR(?film),
          IF(?question = "What movies does Jesse Eisenberg play in?", STR(?film), ""))
    ) AS ?countOrMovie
  )
} 
