```PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?polandPopulation ?smallestCity ?smallestCityArea ?germanyDensityRank WHERE {
  # Population of Poland
  wd:Q36 wdt:P1082 ?polandPopulation .

  # Smallest city by area in Germany
  {
    SELECT ?smallestCity ?smallestCityArea WHERE {
      ?smallestCity wdt:P31/wdt:P279* wd:Q515 ; # instance of city or subclass
                    wdt:P17 wd:Q183 ;           # country Germany
                    wdt:P2046 ?smallestCityArea .
    }
    ORDER BY ?smallestCityArea
    LIMIT 1
  }

  # Population density rank of Germany
  {
    SELECT (COUNT(?country) + 1 AS ?germanyDensityRank) WHERE {
      ?country wdt:P31 wd:Q6256 ;      # instance of country
               wdt:P1082 ?pop ;
               wdt:P2046 ?area .
      BIND(?pop / ?area AS ?density) .
      wd:Q183 wdt:P1082 ?gPop .
      wd:Q183 wdt:P2046 ?gArea .
      BIND(?gPop / ?gArea AS ?gDensity) .
      FILTER(?density > ?gDensity)
    }
  }
}
```

