```PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?germanDensityRank ?germanCityOver250k ?smallestCityByArea WHERE {
  # Population density rank of Germany
  {
    SELECT (COUNT(?country) AS ?germanDensityRank) WHERE {
      ?country wdt:P31 wd:Q6256 ;    # instance of country
               wdt:P1082 ?population ;  # population
               wdt:P2046 ?area .        # area
      FILTER(?area > 0)
      BIND((?population/?area) AS ?density)
      wd:Q183 wdt:P1082 ?germanPopulation .
      wd:Q183 wdt:P2046 ?germanArea .
      BIND((?germanPopulation/?germanArea) AS ?germanDensity)
      FILTER(?density > ?germanDensity)
    }
  }

  # German cities with more than 250000 inhabitants
  OPTIONAL {
    SELECT (GROUP_CONCAT(DISTINCT ?city; separator=", ") AS ?germanCityOver250k) WHERE {
      ?city wdt:P17 wd:Q183 ;   # country Germany
            wdt:P31/wdt:P279* wd:Q515 ;  # instance of city or subclass
            wdt:P1082 ?population .
      FILTER(?population > 250000)
    }
  }

  # Smallest city by area in Germany
  OPTIONAL {
    SELECT ?smallestCityByArea WHERE {
      ?smallestCityByArea wdt:P17 wd:Q183 ;
                          wdt:P31/wdt:P279* wd:Q515 ;
                          wdt:P2046 ?area .
    }
    ORDER BY ?area
    LIMIT 1
  }
}
```

